var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"겨우 이 정도인가요……?","JPN":"この程度ですか……？","ENG":"Is that all you've got...?","TWN":"只有這種程度嗎？"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"……속죄하라.","JPN":"……罪を償え。","ENG":"...Atone.","TWN":"……贖罪吧。"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"크윽, 설마 거울로 모르스의 과거 모습을 불러낼 줄이야……!","JPN":"くっ、まさか鏡でモールスの過去の姿を呼び出すなんて……！","ENG":"Kgh, I didn't expect her to use the mirror to summon Mors's past...!","TWN":"可惡，沒想到竟然能用鏡子召喚出死神過去的樣子！"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이래서는……!","JPN":"これじゃ……！","ENG":"This is bad...!","TWN":"這樣下去！"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"야단났네! 이래서는 최고 등급 재난 경보 때랑 상황이 똑같잖아……?","JPN":"まずい！　これじゃ、最高ランクの災難警報の時と同じ状況だ！","ENG":"We're in deep trouble! This is just like when the highest-level disaster alert went off...!","TWN":"糟糕了！這樣下去和最高級別的災難警報時的情況一模一樣？"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"틀려요, 라이카! 그때는 코치가 있었다고요!","JPN":"違う、ライカ！　あの時はコーチがいたわ！","ENG":"Wrong, Laika! Back then, we had Coach with us!","TWN":"不對，萊卡！那時候有教練在啊！"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하지만 지금은……!","JPN":"でも今は……！","ENG":"But we don't right now...!","TWN":"但現在！"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"관리국 최고 등급 재난 경보라…….","JPN":"管理局の最高ランクの災難警報……","ENG":"The Administration's highest-level disaster alert...","TWN":"管理局最高級別的災難警報……"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하긴, 그때도 코핀 오브 타기리온에서 방출되는 클리파 허수 에너지를 사용했죠.","JPN":"確かに、その時もコフィン・オブ・タギリオンから放出されるクリファ虚数エネルギーを使用しましたね。","ENG":"Well, back then too, we used the Qlipha Imaginary Energy leaking from the Coffin of Thagirion.","TWN":"確實，那時候也使用了從科芬釋放的逆卡巴拉虛空能量。"},"stage":{"bg":"MS_1201","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그건 어디까지나 클리파 차원의 통로에서 새어 나오던 잔류 에너지에 불과해요.","JPN":"ですが、それはあくまでクリファ次元の通路から漏れ出た残留エネルギーに過ぎません。","ENG":"But that was just residual energy seeping through the corridors of the Qlipha Dimension.","TWN":"但那終究只是從逆卡巴拉次元通道洩漏出來的殘餘能量而已。"},"stage":{"bg":"MS_1201","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마왕의 사도로서 직접 클리파 차원에서 끌어 쓰고 있는 힘은 차원이 다를 겁니다.","JPN":"魔王の使徒として、直接クリファ次元から持ち出す力は比べ物にならないでしょう。","ENG":"The power I'm drawing now as an Apostle of the Demon Lord comes directly from the Qlipha Dimension. It's on a completely different scale.","TWN":"作為魔王的使徒，直接從逆卡巴拉次元汲取的力量是截然不同的。"},"stage":{"bg":"MS_1201","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기억의 극장은 제 심상의 풍경이 클리파 허수 에너지를 통해 구현된 형태.","JPN":"記憶の劇場は私の心象風景がクリファ虚数エネルギーによって具現化したもの。","ENG":"The Theater of Memory is a projection of my inner landscape, realized through Qlipha Imaginary Energy.","TWN":"記憶的劇場，是我的心象風景通過逆卡巴拉虛空能量實現的形態。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 한정적인 영역에서는 제 모든 기억은 실체를 갖는답니다.","JPN":"この限られた領域では、私の全ての記憶は実体を持ちます。","ENG":"In this limited space, all of my memories take physical form.","TWN":"在這個有限的領域裡，我的所有記憶都會實體化。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"거울에 비출 대상이 없어도, 기억으로부터 거울상을 끌어올 수 있죠.","JPN":"鏡に映す対象がなくても、記憶から鏡像を引き出すことができる。","ENG":"Even if there's no target reflected in the mirror, I can still summon an image from memory.","TWN":"即使沒有可以映照在鏡子中的物件，也可以從記憶中喚起鏡像。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"그래요, 이를테면…….","JPN":"そうですね、たとえば……","ENG":"Yes, for example...","TWN":"是的，比如說……"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"당신들에게 걸맞은 상대는 이쪽이겠죠, 카나리아 스쿼드.","JPN":"あなたたちに相応しい相手はこちらでしょうか、カナリア・スクワッド。","ENG":"She should be a more fitting opponent for you, Canary Squad.","TWN":"與你們相匹配的對手應該是這邊吧，金絲雀小隊。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"잠깐, 오지만디아스라고……?","JPN":"そんな、オジマンディアス……？","ENG":"Wait, is that Ozymandias...?","TWN":"等等，奧茲曼迪亞斯？"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"꼬맹이, 뒤로 물러나 있어!","JPN":"おこちゃま、後ろに下がってろ！","ENG":"Kid, get back!","TWN":"小鬼，退後待著！"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카! 움직여도 괜찮겠어요? 부상이 심하잖아요!","JPN":"ライカ！　動いて平気なの？　ひどい怪我じゃない！？","ENG":"Laika! You sure you can still fight? You're seriously hurt!","TWN":"萊卡！你能動嗎？傷勢很重啊！？"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그래서? 상대가 저 녀석인데, 내가 널 안 지키면 누가 지키겠냐?","JPN":"だから何？　あいつ相手に、私が守らないと誰があんたを守るんだよ。","ENG":"So what? She's the enemy. If I don't protect you, who will?","TWN":"所以呢？對手是那傢伙，如果我不保護你，誰來保護你呢？"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카…….","JPN":"ライカ……","ENG":"Laika...","TWN":"萊卡……"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};